/** A variant sudoku puzzle */
export type Puzzle = {
  __typename?: 'Puzzle';
  /** Puzzle creator (the owning account) */
  author: User;
  /** Difficulty the setter chose, 1 (gentlest) to 5 (hardest); null if unset */
  authorDifficulty?: Maybe<Scalars['Int']['output']>;
  /** Free-form author credit from the published puzzle's metadata; null when left blank, in which case attribution falls back to the author's display name */
  authorName?: Maybe<Scalars['String']['output']>;
  /** Community difficulty average from solver votes (1–5 scale) */
  avgDifficulty?: Maybe<Scalars['Float']['output']>;
  /** Average star rating from players (1–5 scale) */
  avgRating?: Maybe<Scalars['Float']['output']>;
  /** Custom box region definitions; null means standard 3×3 boxes */
  boxLayout?: Maybe<Scalars['JSON']['output']>;
  /** IDs of the author's collections containing this puzzle; only visible to the author */
  collectionIds: Array<Scalars['ID']['output']>;
  /** Top-level comments, newest first */
  comments: Array<Comment>;
  /** Constraint-type tags from the published version, for archive filtering */
  constraintTypes: Array<Scalars['String']['output']>;
  /** Logical constraints attached to this puzzle */
  constraints: Array<Constraint>;
  /** Visual decorations attached to this puzzle */
  cosmetics: Array<Cosmetic>;
  /** Optional description or story text */
  description?: Maybe<Scalars['String']['output']>;
  /** Difficulty shown in the archive: the community average once there are enough votes, otherwise the setter's value; null until either exists */
  effectiveDifficulty?: Maybe<Scalars['Float']['output']>;
  /** Number of times this puzzle has been favorited */
  favoriteCount: Scalars['Int']['output'];
  /** Whether an admin has featured this puzzle */
  featured: Scalars['Boolean']['output'];
  /** Folder this puzzle is filed in; only visible to the author */
  folder?: Maybe<Folder>;
  /** Pre-filled clue digits keyed by cell coordinate (r0c0: 5) */
  givenDigits: Scalars['JSON']['output'];
  /** Users explicitly granted access to this private puzzle; only visible to the author */
  grantedUsers: Array<User>;
  /** Grid dimensions */
  grid: Grid;
  /** Unique puzzle ID */
  id: Scalars['ID']['output'];
  /** Whether the current user has favorited this puzzle */
  isFavorited: Scalars['Boolean']['output'];
  /** Current user's rating for this puzzle */
  myRating?: Maybe<Rating>;
  /** Linked Patreon campaign for future patron integration */
  patreonCampaignId?: Maybe<Scalars['String']['output']>;
  /** When this puzzle was published */
  publishedAt?: Maybe<Scalars['ISO8601DateTime']['output']>;
  /** The version currently published to solvers */
  publishedVersion?: Maybe<PuzzleVersion>;
  /** Boolean variant flags (diagonals, knights_move, etc.) */
  ruleset: Scalars['JSON']['output'];
  /** Unguessable share/solve URL key; only visible to the author */
  shareToken?: Maybe<Scalars['String']['output']>;
  /** Full solution grid; only visible to the puzzle author */
  solution?: Maybe<Scalars['JSON']['output']>;
  /** SHA-256 of the canonical solution, used for client-side completion detection */
  solutionHash?: Maybe<Scalars['String']['output']>;
  /** Number of times this puzzle has been solved */
  solveCount: Scalars['Int']['output'];
  /** Lifecycle status: draft or published */
  status: PuzzleStatusEnum;
  /** Tags categorizing this puzzle */
  tags: Array<Tag>;
  /** Puzzle title */
  title: Scalars['String']['output'];
  /** All saved versions, oldest first; only visible to the author */
  versions: Array<PuzzleVersion>;
  /** Access mode: private, unlisted, public, patrons_only, subscribers_only, or containers_only */
  visibility: PuzzleVisibilityEnum;
};

