/** Root query type — all queries are composed from domain-specific schema modules */
export type Query = CollectionQueries & PuzzleQueries & SeriesQueries & TagQueries & UserQueries & {
  __typename?: 'Query';
  /** Find a collection by ID, if the current user is allowed to see it */
  collection?: Maybe<Collection>;
  /** Find a collection by its share token (for unlisted/series links) */
  collectionByToken?: Maybe<Collection>;
  /** Ranked solver times for a timed collection (solvers who completed every puzzle) */
  collectionLeaderboard: Array<CollectionLeaderboardEntry>;
  /** Browse the public collection archive with search/filter/sort/pagination */
  collections: CollectionConnection;
  /** The currently authenticated user, or null if unauthenticated */
  me?: Maybe<User>;
  /** A page of the current user's collections, with search/filter/sort */
  myCollections: CollectionConnection;
  /** The current user's top-level folders; nest via each folder's children */
  myFolderTree: Array<Folder>;
  /** The current user's folders, flat, in sort order (for move-target lists) */
  myFolders: Array<Folder>;
  /** A page of puzzles belonging to the current user, with search/filter/sort */
  myPuzzles: PuzzleConnection;
  /** A page of the current user's series, with search/filter/sort */
  mySeries: SeriesConnection;
  /** Series the current user is subscribed to, newest subscription first */
  mySubscriptions: Array<Series>;
  /** Browse the public series archive with search/filter/sort/pagination */
  publicSeries: SeriesConnection;
  /** Find a puzzle by ID, if the current user is allowed to see it */
  puzzle?: Maybe<Puzzle>;
  /** Find a puzzle by its share token (used for unlisted/solve links) */
  puzzleByToken?: Maybe<Puzzle>;
  /** Distinct grid sizes present in the published archive, with counts, for the size facet */
  puzzleGridSizes: Array<GridSize>;
  /** Fetch a single version's full content for editing or restore (author only) */
  puzzleVersion?: Maybe<PuzzleVersion>;
  /** Browse the published puzzle archive with search/filter/sort/pagination */
  puzzles: PuzzleConnection;
  /** Find a series by ID, if the current user is allowed to see it */
  series?: Maybe<Series>;
  /** Find a series by its share token (for unlisted links) */
  seriesByToken?: Maybe<Series>;
  /** Recently-released entries across the current user's subscribed series, newest first */
  seriesFeed: Array<SeriesEntry>;
  /** All available tags, ordered alphabetically */
  tags: Array<Tag>;
  /** Find a user by username */
  user?: Maybe<User>;
};


